const diff = $input.item.json.diff ?? '';

const lines = diff
  .replace(/\n\\ No newline at end of file/g, '')
  .split('\n');

let originalCode = '';
let newCode = '';
let newCodeLogicalLine = 0;
const newCodeLineMap = {};

let oldLine = 0;
let newLine = 0;

let reviewableNewCode = '';

for (const line of lines) {
  const hunk = line.match(/^@@ -(\d+)(?:,\d+)? \+(\d+)(?:,\d+)? @@/);
  if (hunk) {
    oldLine = Number(hunk[1]);
    newLine = Number(hunk[2]);
    continue;
  }

  if (line.startsWith('+++') || line.startsWith('---')) {
    continue;
  }

  if (line.startsWith('-')) {
    originalCode += line + '\n';
    oldLine += 1;
    continue;
  }

  if (line.startsWith('+')) {
    newCode += line + '\n';
    newCodeLogicalLine += 1;
    newCodeLineMap[newCodeLogicalLine] = newLine;
    reviewableNewCode += `[L${newLine}] ${line}\n`;
    newLine += 1;
    continue;
  }

  // context line
  newCode += line + '\n';
  newCodeLogicalLine += 1;
  newCodeLineMap[newCodeLogicalLine] = newLine;
  reviewableNewCode += `[L${newLine}] ${line}\n`;
  oldLine += 1;
  newLine += 1;
}

return {
  path: $input.item.json.new_path || $input.item.json.old_path || '',
  oldPath: $input.item.json.old_path || '',
  newPath: $input.item.json.new_path || '',
  gitDiff: diff,
  originalCode,
  newCode,
  newCodeLineMap,
  reviewableNewCode,
  mrTitle: $('GitLab Discussion Webhook').item.json.body.merge_request.title || '',
  mrDescription: $('GitLab Discussion Webhook').item.json.body.merge_request.description || '',
  projectId: $('GitLab Discussion Webhook').item.json.body.project.id,
  mrIid: $('GitLab Discussion Webhook').item.json.body.merge_request.iid,
  discussionId: $('GitLab Discussion Webhook').item.json.body.object_attributes.discussion_id,
  startSha: $('Fetch Merge Request Changes').item.json.diff_refs.start_sha || '',
  headSha: $('Fetch Merge Request Changes').item.json.diff_refs.head_sha || '',
  baseSha: $('Fetch Merge Request Changes').item.json.diff_refs.base_sha || ''
};

const allItems = $input.all();

let merged = [];

// Assuming that the reviewer’s output is stored in item.json.output
for (const item of allItems) {
  const src = item.json.output ?? item.json;
  const findings = src.findings || [];
  merged = merged.concat(findings);
}

const uniqueMap = new Map();

for (const f of merged) {
  const key = `${f.title}_${f.path}_${f.line}`;
  if (!uniqueMap.has(key)) {
    uniqueMap.set(key, f);
  }
}

return [
  {
    json: {
      path: $('Prepare Review Context').first().json.path || '',
      oldPath: $('Prepare Review Context').first().json.oldPath || '',
      newPath: $('Prepare Review Context').first().json.newPath || '',
      gitDiff: $('Prepare Review Context').first().json.gitDiff || '',
      originalCode: $('Prepare Review Context').first().json.originalCode || '',
      newCode: $('Prepare Review Context').first().json.newCode || '',
      newCodeLineMap: $('Prepare Review Context').first().json.newCodeLineMap || {},
      reviewableNewCode: $('Prepare Review Context').first().json.reviewableNewCode || '',
      mrTitle: $('Prepare Review Context').first().json.mrTitle || '',
      mrDescription: $('Prepare Review Context').first().json.mrDescription || '',
      projectId: $('Prepare Review Context').first().json.projectId || '',
      mrIid: $('Prepare Review Context').first().json.mrIid || '',
      discussionId: $('Prepare Review Context').first().json.discussionId || '',
      startSha: $('Prepare Review Context').first().json.startSha || '',
      headSha: $('Prepare Review Context').first().json.headSha || '',
      baseSha: $('Prepare Review Context').first().json.baseSha || '',
      findings: Array.from(uniqueMap.values())
    }
  }
];

