parameters.jsCode:
const out = $json.output ?? $json;
const meta = $('Combine Findings').first().json;

const validatedFindings = (out.validated_findings || []).map(f => {
  const rawLine = f.line;
  const line = Number(rawLine);
  const lineMap = meta.newCodeLineMap || {};
  const mappedLine = Number.isInteger(line) && line > 0
    ? Number(lineMap[line] ?? line)
    : null;

  const normalizedLine =
    Number.isInteger(mappedLine) && mappedLine > 0 ? mappedLine : null;

  const normalizedStatus = f.status || 'drop';
  const normalizedInline =
    normalizedStatus === 'keep' &&
    normalizedLine !== null &&
    f.post_inline === true;

  return {
    ...f,
    path: f.path && f.path !== 'unknown' ? f.path : (meta.path || ''),
    oldPath: meta.oldPath || '',
    newPath: meta.newPath || '',
    projectId: meta.projectId || '',
    mrIid: meta.mrIid || '',
    discussionId: meta.discussionId || '',
    startSha: meta.startSha || '',
    headSha: meta.headSha || '',
    baseSha: meta.baseSha || '',
    line: normalizedLine,
    post_inline: normalizedInline
  };
});

const keepCount = validatedFindings.filter(f => f.status === 'keep').length;

return [
  {
    json: {
      validated_findings: validatedFindings,
      keep_count: keepCount
    }
  }
];

return {
  text: $('Workflow Configuration').first().json.summaryMessage
    || '✅ Review finished. See inline comments for details.'
};

const iconMap = {
  high: "🔴",
  medium: "🟡",
  low: "🔵",
};

const icon = iconMap[$json.final_severity] || "🔵";

return {
  ...$json,
  text: `${icon} **${$json.title}**\n\n${$json.comment}`
};

const diff = $('Combine Findings').first().json.gitDiff || '';
const targetLine = Number($json.line);

function buildNewSideMap(gitDiff) {
  const lines = gitDiff.replace(/\n\\ No newline at end of file/g, '').split('\n');

  let oldLine = 0;
  let newLine = 0;
  const map = new Map();

  for (const line of lines) {
    const hunk = line.match(/^@@ -(\d+)(?:,\d+)? \+(\d+)(?:,\d+)? @@/);
    if (hunk) {
      oldLine = Number(hunk[1]);
      newLine = Number(hunk[2]);
      continue;
    }

    if (line.startsWith('+++') || line.startsWith('---')) {
      continue;
    }

    if (line.startsWith('+')) {
      map.set(newLine, {
        kind: 'added',
        newLine,
        oldLine: null,
      });
      newLine += 1;
      continue;
    }

    if (line.startsWith('-')) {
      oldLine += 1;
      continue;
    }

    // context line
    map.set(newLine, {
      kind: 'context',
      newLine,
      oldLine,
    });
    oldLine += 1;
    newLine += 1;
  }

  return map;
}

const lineMap = buildNewSideMap(diff);
const pos = lineMap.get(targetLine);

return {
  ...$json,
  positionKind: pos?.kind || 'unknown',
  positionNewLine: pos?.newLine ?? null,
  positionOldLine: pos?.oldLine ?? null,
  canPostInline: !!pos
};

const iconMap = {
  high: '🔴',
  medium: '🟡',
  low: '🔵',
};

const severity = ($json.final_severity || 'low').toLowerCase();
const icon = iconMap[severity] || '🔵';

return {
  ...$json,
  fallbackBody: [
    `${icon} General review comment (exact diff line could not be resolved)`,
    '',
    `**${$json.title}**`,
    $json.comment,
    '',
    `File: ${$json.path || $json.newPath || $json.oldPath || 'unknown'}`
  ].join('\n')
};
